// Send broadcast email via dashboard Gmail OAuth token
const tokenRes = await this.helpers.httpRequest({
  method: 'GET',
  url: ($env.DASHBOARD_INTERNAL_URL || 'http://pm-dash:3000') + '/api/auth/google/token',
  json: true,
  timeout: 10000
});

if (!tokenRes.access_token) {
  // Gmail not connected — notify owner via Telegram
const ownerChatId = $env.TELEGRAM_OWNER_CHAT_ID || '6216258938';
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
    body: { chat_id: ownerChatId, text: '⚠️ Gmail disconnected — email could not be sent. Please reconnect Gmail on the dashboard Settings page.' },
    json: true,
    timeout: 10000
  });
} catch (e) {}
return [{ json: { sent: false, error: 'Gmail not connected' } }];
}

const body = $json.body || $json;
const to = body.email || $json.email;
const subject = body.subject || $json.subject || 'Julia Inc - Property Management';
const text = body.text || $json.text || '';
const fromEmail = tokenRes.email || '';

const rawEmail = `From: ${fromEmail}\r\nTo: ${to}\r\nSubject: ${subject}\r\nContent-Type: text/plain; charset=utf-8\r\n\r\n${text}`;
const encoded = Buffer.from(rawEmail).toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');

const sendRes = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://gmail.googleapis.com/gmail/v1/users/me/messages/send',
  headers: { 'Authorization': 'Bearer ' + tokenRes.access_token, 'Content-Type': 'application/json' },
  body: JSON.stringify({ raw: encoded }),
  json: true,
  timeout: 15000
});

return [{ json: { sent: true, id: sendRes.id, to, subject } }];
